document.addEventListener("DOMContentLoaded", function () {
    const carousel = document.querySelector("#carousel")
    const track = carousel.querySelector(".carousel-track")
    const prev = carousel.querySelector(".prev")
    const next = carousel.querySelector(".next")
    const dotsWrap = carousel.querySelector(".dots")

    let slides = carousel.querySelectorAll(".slide")

    let index = 1
    let slideWidth = slides[0].offsetWidth

    let startX = 0
    let currentX = 0
    var isDragging = false
    let isAnimating = false

    // clone slide
    const firstClone = slides[0].cloneNode(true)
    const lastClone = slides[slides.length - 1].cloneNode(true)

    track.appendChild(firstClone)
    track.insertBefore(lastClone, slides[0])

    slides = carousel.querySelectorAll(".slide")

    function setPosition() {
        slideWidth = slides[0].offsetWidth
        track.style.transition = "none"
        track.style.transform = `translateX(-${slideWidth * index}px)`
    }

    window.addEventListener("resize", setPosition)

    setPosition()

    // dots
    slides.forEach((_, i) => {

        if (i === 0 || i === slides.length - 1) return

        const dot = document.createElement("div")
        dot.className = "dot"

        if (i === 1) dot.classList.add("active")

        dot.onclick = () => {
            if (isAnimating) return
            index = i
            move()
        }

        dotsWrap.appendChild(dot)
    })

    const dots = dotsWrap.querySelectorAll(".dot")

    function updateDots() {

        dots.forEach(d => d.classList.remove("active"))

        let i = index - 1

        if (i < 0) i = dots.length - 1
        if (i >= dots.length) i = 0

        dots[i].classList.add("active")
    }

    // move slide
    function move() {

        if (isAnimating) return

        isAnimating = true

        track.style.transition = "transform .4s ease"
        track.style.transform = `translateX(-${slideWidth * index}px)`

        updateDots()
    }

    next.onclick = () => {
        if (isAnimating) return
        index++
        move()
    }

    prev.onclick = () => {
        if (isAnimating) return
        index--
        move()
    }

    // infinite loop
    track.addEventListener("transitionend", () => {

        isAnimating = false

        if (index === slides.length - 1) {

            track.style.transition = "none"
            index = 1
            track.style.transform = `translateX(-${slideWidth * index}px)`
        }

        if (index === 0) {

            track.style.transition = "none"
            index = slides.length - 2
            track.style.transform = `translateX(-${slideWidth * index}px)`
        }
    })

    // autoplay
    let autoplay = setInterval(() => {
        next.click()
    }, 10000)

    carousel.addEventListener("mouseenter", () => clearInterval(autoplay))

    carousel.addEventListener("mouseleave", () => {
        autoplay = setInterval(() => next.click(), 10000)
    })

    // drag start
    function startDrag(e) {

        if (isAnimating) return

        clearInterval(autoplay) // thêm dòng này

        isDragging = true

        startX = e.touches ? e.touches[0].clientX : e.clientX
        currentX = startX

        track.style.transition = "none"

        document.addEventListener("mousemove", drag)
        document.addEventListener("touchmove", drag)

        document.addEventListener("mouseup", endDrag)
        document.addEventListener("touchend", endDrag)
    }

    // dragging
    function drag(e) {

        if (!isDragging) return

        currentX = e.touches ? e.touches[0].clientX : e.clientX

        const diff = currentX - startX

        track.style.transform = `translateX(${-(slideWidth * index) + diff}px)`
    }

    // drag end
    function endDrag() {

        if (!isDragging) return

        isDragging = false

        const diff = currentX - startX

        if (diff < -80) index++
        if (diff > 80) index--

        move()
        autoplay = setInterval(() => next.click(), 10000) // restart
        document.removeEventListener("mousemove", drag)
        document.removeEventListener("touchmove", drag)
        document.removeEventListener("mouseup", endDrag)
        document.removeEventListener("touchend", endDrag)
    }

    track.addEventListener("mousedown", startDrag)
    track.addEventListener("touchstart", startDrag)
})